import React, { useMemo } from 'react';
import { Box, Typography, alpha } from '@mui/material';
import { sectionLabelSx } from '@som/ui';
import { ITEMS } from '../../data/mockItems';
import { COLORS } from '../../data/categories';
import { CatIcon } from '../shared/CatIcon';
import { StarsDisplay } from '../shared/StarRating';
import type { ResourceItem } from '../../types';

interface PopularSectionProps {
    onSelect: (item: ResourceItem) => void;
}

export const PopularSection: React.FC<PopularSectionProps> = ({ onSelect }) => {
    const offices = [...new Set(ITEMS.map((i) => i.office).filter((o) => o !== 'Firmwide'))];
    const office = useMemo(() => offices[Math.floor(Math.random() * offices.length)], []);
    const officeItems = useMemo(
        () =>
            ITEMS.filter((i) => i.office === office && i.kind === 'use')
                .sort((a, b) => b.uses - a.uses)
                .slice(0, 5),
        [office]
    );

    if (officeItems.length === 0) return null;

    return (
        <Box sx={{ mb: 3.5 }}>
            <Typography
                variant="overline"
                color="text.disabled"
                sx={{ ...sectionLabelSx, display: 'block', mb: 1.75 }}
            >
                Popular in {office}
            </Typography>
            <Box
                sx={{
                    display: 'flex',
                    gap: 1,
                    overflowX: 'auto',
                    pb: 1,
                    scrollSnapType: 'x mandatory',
                    '&::-webkit-scrollbar': { height: 4 },
                    '&::-webkit-scrollbar-thumb': { bgcolor: 'divider', borderRadius: 2 },
                }}
            >
                {officeItems.map((item) => (
                    <Box
                        key={item.id}
                        onClick={() => onSelect(item)}
                        sx={{
                            flexShrink: 0,
                            width: 240,
                            bgcolor: 'background.paper',
                            border: '1px solid',
                            borderColor: 'divider',
                            borderRadius: 1,
                            p: 1.75,
                            cursor: 'pointer',
                            scrollSnapAlign: 'start',
                            transition: 'all 0.15s ease',
                            '&:hover': {
                                bgcolor: 'action.hover',
                                borderColor: 'text.disabled',
                            },
                        }}
                    >
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75, mb: 1 }}>
                            <CatIcon category={item.category} size={12} />
                            <Typography
                                variant="overline"
                                sx={{ color: COLORS[item.category], letterSpacing: '0.1em', lineHeight: 1 }}
                            >
                                {item.category}
                            </Typography>
                        </Box>
                        <Typography variant="h5" sx={{ fontWeight: 400, lineHeight: 1.25, mb: 0.75 }}>
                            {item.title}
                        </Typography>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75 }}>
                            <StarsDisplay rating={item.rating} size={8} />
                            <Typography variant="caption" color="text.disabled" sx={{ fontFamily: 'monospace' }}>
                                {item.uses} uses
                            </Typography>
                        </Box>
                    </Box>
                ))}
            </Box>
        </Box>
    );
};

import React from 'react';
import { Box, Typography, Chip, useTheme, alpha } from '@mui/material';
import { hoverCardSx } from '@som/ui';
import type { ResourceItem, Tip } from '../../types';
import { COLORS } from '../../data/categories';
import { CatIcon } from '../shared/CatIcon';
import { StarsDisplay } from '../shared/StarRating';
import { VerifiedBadge } from '../shared/VerifiedBadge';

interface ResourceCardProps {
    item: ResourceItem;
    index: number;
    onClick: (item: ResourceItem) => void;
    compact?: boolean;
}

const TODAY = new Date('2026-02-25');
const daysAgo = (d: string) => Math.floor((TODAY.getTime() - new Date(d).getTime()) / 86400000);

const NewBadge: React.FC<{ date: string }> = ({ date }) => {
    const d = daysAgo(date);
    if (d > 7) return null;
    const label = d <= 1 ? 'Today' : d <= 3 ? `${d}d ago` : 'New';
    return (
        <Chip
            label={label}
            size="small"
            sx={{
                height: 16,
                fontSize: '8px',
                fontWeight: 600,
                bgcolor: (t) => alpha(t.palette.success.main, 0.12),
                color: 'success.main',
                '& .MuiChip-label': { px: 0.75 },
            }}
        />
    );
};

export const ResourceCard: React.FC<ResourceCardProps> = ({ item, index, onClick, compact }) => {
    const theme = useTheme();
    const isLearn = item.kind === 'learn';
    const accentColor = COLORS[item.category];
    const topTip: Tip | null =
        item.tips.length > 0 ? [...item.tips].sort((a, b) => b.votes - a.votes)[0] : null;

    return (
        <Box
            onClick={() => onClick(item)}
            sx={{
                bgcolor: 'background.paper',
                borderRadius: 1,
                cursor: 'pointer',
                overflow: 'hidden',
                border: '1px solid',
                borderColor: 'divider',
                display: 'flex',
                flexDirection: 'column',
                animation: `fadeUp 0.4s ease ${index * 0.03}s both`,
                height: '100%',
                transition: 'all 0.2s ease',
                '&:hover': {
                    bgcolor: 'action.hover',
                    borderColor: 'text.disabled',
                    transform: 'translateY(-2px)',
                },
            }}
        >
            {/* Category accent bar */}
            <Box sx={{ height: 2, bgcolor: accentColor, opacity: 0.5, transition: 'opacity 0.2s', '&:hover': { opacity: 0.85 } }} />

            <Box sx={{ p: compact ? 1.75 : 2, flex: 1, display: 'flex', flexDirection: 'column' }}>
                {/* Header: category icon + type badges */}
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 1 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75 }}>
                        <Box
                            sx={{
                                width: 28,
                                height: 28,
                                borderRadius: '6px',
                                bgcolor: alpha(accentColor, 0.08),
                                border: '1px solid',
                                borderColor: alpha(accentColor, 0.15),
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                            }}
                        >
                            <CatIcon category={item.category} size={14} />
                        </Box>
                        <Typography
                            variant="overline"
                            sx={{ color: accentColor, letterSpacing: '0.1em', lineHeight: 1 }}
                        >
                            {item.category}
                        </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', gap: 0.5, alignItems: 'center' }}>
                        <NewBadge date={item.date} />
                        {isLearn && (
                            <Chip
                                label="Guide"
                                size="small"
                                sx={{
                                    height: 16,
                                    fontSize: '8px',
                                    bgcolor: 'action.selected',
                                    color: 'text.disabled',
                                    '& .MuiChip-label': { px: 0.75 },
                                }}
                            />
                        )}
                        {item.verified && <VerifiedBadge />}
                    </Box>
                </Box>

                {/* Title */}
                <Typography
                    variant="h4"
                    sx={{ mb: 0.625, lineHeight: 1.25, fontWeight: 400 }}
                >
                    {item.title}
                </Typography>

                {/* Description */}
                <Typography
                    variant="body2"
                    color="text.secondary"
                    sx={{
                        mb: 1.25,
                        flex: 1,
                        display: '-webkit-box',
                        WebkitLineClamp: compact ? 2 : 3,
                        WebkitBoxOrient: 'vertical',
                        overflow: 'hidden',
                        lineHeight: 1.5,
                    }}
                >
                    {item.description}
                </Typography>

                {/* Top tip preview */}
                {topTip && !compact && (
                    <Box
                        sx={{
                            bgcolor: 'background.default',
                            borderRadius: '4px',
                            p: '8px 10px',
                            mb: 1.25,
                            borderLeft: `2px solid ${alpha(accentColor, 0.3)}`,
                        }}
                    >
                        <Typography
                            variant="body2"
                            color="text.disabled"
                            sx={{
                                lineHeight: 1.45,
                                display: '-webkit-box',
                                WebkitLineClamp: 2,
                                WebkitBoxOrient: 'vertical',
                                overflow: 'hidden',
                            }}
                        >
                            &ldquo;{topTip.text}&rdquo;
                        </Typography>
                        <Typography variant="caption" color="text.disabled" sx={{ mt: 0.25, display: 'block' }}>
                            — {topTip.author} · ▲ {topTip.votes}
                        </Typography>
                    </Box>
                )}

                {/* Tags */}
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, mb: 1.375 }}>
                    {item.tags.slice(0, 3).map((t) => (
                        <Chip
                            key={t}
                            label={t}
                            size="small"
                            variant="outlined"
                            sx={{
                                height: 18,
                                fontSize: '9px',
                                fontFamily: 'monospace',
                                '& .MuiChip-label': { px: 0.75 },
                            }}
                        />
                    ))}
                </Box>

                {/* Footer */}
                <Box
                    sx={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        pt: 1,
                        borderTop: '1px solid',
                        borderColor: 'divider',
                    }}
                >
                    {/* Author */}
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75 }}>
                        <Box
                            sx={{
                                width: 19,
                                height: 19,
                                borderRadius: '50%',
                                bgcolor: alpha(accentColor, 0.1),
                                color: accentColor,
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: '8px',
                                fontWeight: 700,
                            }}
                        >
                            {item.author.split(' ').map((n) => n[0]).join('')}
                        </Box>
                        <Typography variant="caption" color="text.secondary">
                            {item.author}
                        </Typography>
                        <Typography variant="caption" color="text.disabled">·</Typography>
                        <Typography variant="caption" color="text.disabled">
                            {item.office}
                        </Typography>
                    </Box>

                    {/* Stats */}
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        {item.tips.length > 0 && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.25 }}>
                                <Box component="span" sx={{ fontSize: 10, color: 'text.disabled' }}>💬</Box>
                                <Typography variant="caption" color="text.disabled">{item.tips.length}</Typography>
                            </Box>
                        )}
                        <StarsDisplay rating={item.rating} size={9} />
                        {item.uses >= 10 && (
                            <Typography variant="caption" color="text.disabled" sx={{ fontFamily: 'monospace' }}>
                                {item.uses}
                            </Typography>
                        )}
                    </Box>
                </Box>
            </Box>
        </Box>
    );
};

import React, { useRef, useEffect, useMemo } from 'react';
import { useAtom } from 'jotai';
import { Box, Typography, Chip, Button, Paper } from '@mui/material';
import { sectionLabelSx } from '@som/ui';
import { facetsAtom } from '../../atoms/filterAtoms';
import { ITEMS } from '../../data/mockItems';
import type { FacetFilters } from '../../types';

interface FacetPanelProps {
    onClose: () => void;
}

export const FacetPanel: React.FC<FacetPanelProps> = ({ onClose }) => {
    const [filters, setFilters] = useAtom(facetsAtom);
    const ref = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const h = (e: MouseEvent) => {
            if (ref.current && !ref.current.contains(e.target as Node)) onClose();
        };
        document.addEventListener('mousedown', h);
        return () => document.removeEventListener('mousedown', h);
    }, [onClose]);

    const items = ITEMS;
    const allDisc = useMemo(() => [...new Set(items.map((i) => i.discipline))].sort(), [items]);
    const allOffice = useMemo(() => [...new Set(items.map((i) => i.office))].sort(), [items]);
    const allAuthors = useMemo(() => [...new Set(items.map((i) => i.author))].sort(), [items]);
    const allTags = useMemo(() => [...new Set(items.flatMap((i) => i.tags))].sort(), [items]);

    const toggle = (k: keyof FacetFilters, v: string) => {
        const arr = filters[k];
        setFilters({
            ...filters,
            [k]: arr.includes(v) ? arr.filter((x) => x !== v) : [...arr, v],
        });
    };

    const ct = Object.values(filters).reduce((s, a) => s + a.length, 0);

    const Section = ({
        title,
        data,
        filterKey,
    }: {
        title: string;
        data: [string, number][];
        filterKey: keyof FacetFilters;
    }) => (
        <Box sx={{ mb: 1.5 }}>
            <Typography variant="overline" color="text.disabled" sx={{ ...sectionLabelSx, display: 'block', mb: 0.75 }}>
                {title}
            </Typography>
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>
                {data.map(([v, c]) => {
                    const active = filters[filterKey].includes(v);
                    return (
                        <Chip
                            key={v}
                            label={`${v} (${c})`}
                            onClick={() => toggle(filterKey, v)}
                            size="small"
                            variant={active ? 'filled' : 'outlined'}
                            sx={{ cursor: 'pointer', fontSize: '10px' }}
                        />
                    );
                })}
            </Box>
        </Box>
    );

    return (
        <Paper
            ref={ref}
            elevation={0}
            sx={{
                position: 'absolute',
                top: '100%',
                left: 0,
                right: 0,
                mt: 0.75,
                bgcolor: 'background.paper',
                border: '1px solid',
                borderColor: 'divider',
                borderRadius: 1,
                p: 2.25,
                zIndex: 50,
                animation: 'fadeUp 0.2s ease',
            }}
        >
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.75 }}>
                <Typography variant="h5">Filters</Typography>
                {ct > 0 && (
                    <Button
                        size="small"
                        variant="text"
                        onClick={() => setFilters({ tags: [], offices: [], disciplines: [], authors: [] })}
                        sx={{ fontSize: '10px', color: 'text.secondary' }}
                    >
                        Clear all ({ct})
                    </Button>
                )}
            </Box>
            <Section
                title="Discipline"
                data={allDisc.map((d) => [d, items.filter((i) => i.discipline === d).length])}
                filterKey="disciplines"
            />
            <Section
                title="Office"
                data={allOffice.map((o) => [o, items.filter((i) => i.office === o).length])}
                filterKey="offices"
            />
            <Section
                title="Author"
                data={allAuthors.map((a) => [a, items.filter((i) => i.author === a).length])}
                filterKey="authors"
            />
            <Section
                title="Tags"
                data={allTags.map((t) => [t, items.filter((i) => i.tags.includes(t)).length])}
                filterKey="tags"
            />
        </Paper>
    );
};

import React, { useState } from 'react';
import { useAtom, useAtomValue } from 'jotai';
import {
    Box, Typography, Chip, Select, MenuItem, ToggleButtonGroup, ToggleButton,
    type SelectChangeEvent,
} from '@mui/material';
import { GridView, ViewList, FilterList } from '@mui/icons-material';
import { StandardSearchInput } from '@som/ui';
import {
    searchAtom,
    categoryAtom,
    sortAtom,
    viewAtom,
    facetCountAtom,
} from '../../atoms/filterAtoms';
import { CATEGORIES, SORT_OPTIONS, COLORS } from '../../data/categories';
import { useRotatingHint } from '../../hooks/useRotatingHint';
import { FacetPanel } from './FacetPanel';
import type { CategoryName } from '../../types';

interface LibraryFilterBarProps {
    total: number;
}

export const LibraryFilterBar: React.FC<LibraryFilterBarProps> = ({ total }) => {
    const [search, setSearch] = useAtom(searchAtom);
    const [category, setCategory] = useAtom(categoryAtom);
    const [sort, setSort] = useAtom(sortAtom);
    const [view, setView] = useAtom(viewAtom);
    const facetCount = useAtomValue(facetCountAtom);
    const [showFacets, setShowFacets] = useState(false);
    const placeholder = useRotatingHint();

    return (
        <Box sx={{ position: 'relative', mb: 2.5 }}>
            {/* Search */}
            <StandardSearchInput
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                onClear={() => setSearch('')}
                placeholder={placeholder}
                sx={{ mb: 1.5 }}
                fullWidth
            />

            {/* Controls row */}
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75, flexWrap: 'wrap' }}>
                {/* Category chips */}
                <Box sx={{ display: 'flex', gap: 0.5, flex: 1, flexWrap: 'wrap' }}>
                    {CATEGORIES.map((c) => {
                        const active = category === c;
                        const accentColor = c !== 'All' ? COLORS[c as CategoryName] : undefined;
                        return (
                            <Chip
                                key={c}
                                label={
                                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                        {c !== 'All' && (
                                            <Box
                                                component="span"
                                                sx={{
                                                    width: 6,
                                                    height: 6,
                                                    borderRadius: '50%',
                                                    bgcolor: accentColor,
                                                    opacity: active ? 1 : 0.4,
                                                    display: 'inline-block',
                                                }}
                                            />
                                        )}
                                        {c}
                                    </Box>
                                }
                                onClick={() => setCategory(c)}
                                size="small"
                                variant={active ? 'filled' : 'outlined'}
                                sx={{
                                    cursor: 'pointer',
                                    ...(active && accentColor ? {
                                        bgcolor: `${accentColor}18`,
                                        borderColor: `${accentColor}55`,
                                        color: accentColor,
                                    } : {}),
                                }}
                            />
                        );
                    })}
                </Box>

                {/* Facet toggle */}
                <Chip
                    icon={<FilterList sx={{ fontSize: 14 }} />}
                    label={`Filters${facetCount > 0 ? ` (${facetCount})` : ''}`}
                    onClick={() => setShowFacets(!showFacets)}
                    size="small"
                    variant={facetCount > 0 ? 'filled' : 'outlined'}
                    sx={{ cursor: 'pointer' }}
                />

                {/* Sort */}
                <Select
                    value={sort}
                    onChange={(e: SelectChangeEvent) => setSort(e.target.value as any)}
                    size="small"
                    variant="outlined"
                    sx={{
                        fontSize: '11px',
                        height: 28,
                        '& .MuiSelect-select': { py: 0.5, px: 1.25 },
                    }}
                >
                    {SORT_OPTIONS.map((s) => (
                        <MenuItem key={s} value={s} sx={{ fontSize: '11px' }}>{s}</MenuItem>
                    ))}
                </Select>

                {/* View toggle */}
                <ToggleButtonGroup
                    value={view}
                    exclusive
                    onChange={(_, v) => v && setView(v)}
                    size="small"
                >
                    <ToggleButton value="grid" sx={{ px: 1, py: 0.5 }}>
                        <GridView sx={{ fontSize: 14 }} />
                    </ToggleButton>
                    <ToggleButton value="list" sx={{ px: 1, py: 0.5 }}>
                        <ViewList sx={{ fontSize: 14 }} />
                    </ToggleButton>
                </ToggleButtonGroup>

                {/* Count */}
                <Typography variant="caption" color="text.disabled" sx={{ fontFamily: 'monospace', whiteSpace: 'nowrap' }}>
                    {total} results
                </Typography>
            </Box>

            {/* Facet panel */}
            {showFacets && <FacetPanel onClose={() => setShowFacets(false)} />}
        </Box>
    );
};

import React, { useState } from 'react';
import {
    Box,
    Typography,
    Button,
    ToggleButton,
    ToggleButtonGroup,
    TextField,
} from '@mui/material';
import { StandardDialog, FormField, StandardSelect } from '@som/ui';
import { CATEGORIES } from '../../data/categories';
import { DISCIPLINES } from '../../data/disciplines';
import { TagInput } from '../shared/TagInput';

interface ContributeModalProps {
    onClose: () => void;
}

export const ContributeModal: React.FC<ContributeModalProps> = ({ onClose }) => {
    const [step, setStep] = useState(1);
    const [form, setForm] = useState({
        kind: 'use' as 'use' | 'learn',
        name: '',
        desc: '',
        type: 'Gems',
        discipline: 'General',
        link: '',
        prompt: '',
    });
    const [tags, setTags] = useState<string[]>([]);

    const upd = (k: string, v: any) => setForm({ ...form, [k]: v });

    return (
        <StandardDialog
            open={true}
            onClose={onClose}
            title={step === 1 ? 'Contribute' : 'Almost There'}
            actions={
                <Box sx={{ display: 'flex', justifyContent: 'space-between', width: '100%', px: 1, pb: 1 }}>
                    {step === 1 ? (
                        <>
                            <Box />
                            <Button variant="contained" onClick={() => setStep(2)}>
                                Next
                            </Button>
                        </>
                    ) : (
                        <>
                            <Button variant="outlined" onClick={() => setStep(1)} sx={{ borderColor: 'divider' }}>
                                Back
                            </Button>
                            <Button variant="contained" color="success" onClick={onClose}>
                                Submit
                            </Button>
                        </>
                    )}
                </Box>
            }
        >
            <Box
                sx={{
                    height: 3,
                    background: 'linear-gradient(90deg,#D4845A,#6AADCF,#CBAA5E,#E07BA0,#B494D0,#8BC78A)',
                    mt: -2.5,
                    mx: -3,
                    mb: 2.5
                }}
            />

            {/* Step Indicator */}
            <Box sx={{ display: 'flex', gap: 1, mb: 3 }}>
                {[1, 2].map((s) => (
                    <Box
                        key={s}
                        sx={{
                            height: 2,
                            flex: 1,
                            borderRadius: 1,
                            bgcolor: step >= s ? 'primary.main' : 'divider',
                            transition: 'background 0.3s',
                        }}
                    />
                ))}
            </Box>

            {step === 1 ? (
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2.5 }}>
                    <ToggleButtonGroup
                        value={form.kind}
                        exclusive
                        onChange={(_, v) => v && upd('kind', v)}
                        fullWidth
                    >
                        <ToggleButton value="use" sx={{ py: 1.5, display: 'flex', flexDirection: 'column', gap: 0.5 }}>
                            <Typography variant="h4">🔧</Typography>
                            <Typography variant="caption" sx={{ fontWeight: 600 }}>Share a Tool</Typography>
                        </ToggleButton>
                        <ToggleButton value="learn" sx={{ py: 1.5, display: 'flex', flexDirection: 'column', gap: 0.5 }}>
                            <Typography variant="h4">📖</Typography>
                            <Typography variant="caption" sx={{ fontWeight: 600 }}>Write a Guide</Typography>
                        </ToggleButton>
                    </ToggleButtonGroup>

                    <FormField label="Name">
                        <TextField
                            fullWidth
                            size="small"
                            placeholder="Give it a clear, descriptive name"
                            value={form.name}
                            onChange={(e: React.ChangeEvent<HTMLInputElement>) => upd('name', e.target.value)}
                        />
                    </FormField>

                    <FormField label="Description">
                        <TextField
                            fullWidth
                            multiline
                            rows={3}
                            placeholder="How does this help the firm?"
                            value={form.desc}
                            onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => upd('desc', e.target.value)}
                        />
                    </FormField>

                    <Box sx={{ display: 'flex', gap: 2 }}>
                        <FormField label="Category" sx={{ flex: 1 }}>
                            <StandardSelect
                                value={form.type}
                                onChange={(e: any) => upd('type', e.target.value)}
                                options={CATEGORIES.filter((c) => c !== 'All').map(c => ({ label: c, value: c }))}
                            />
                        </FormField>
                        <FormField label="Discipline" sx={{ flex: 1 }}>
                            <StandardSelect
                                value={form.discipline}
                                onChange={(e: any) => upd('discipline', e.target.value)}
                                options={DISCIPLINES.map(d => ({ label: d, value: d }))}
                            />
                        </FormField>
                    </Box>
                </Box>
            ) : (
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2.5 }}>
                    <FormField label="Link">
                        <TextField
                            fullWidth
                            size="small"
                            placeholder="Paste the URL to your resource"
                            value={form.link}
                            onChange={(e: React.ChangeEvent<HTMLInputElement>) => upd('link', e.target.value)}
                        />
                    </FormField>

                    <TagInput tags={tags} setTags={setTags} />

                    <FormField label="Prompt / Instructions (Optional)">
                        <TextField
                            fullWidth
                            multiline
                            rows={3}
                            placeholder="Paste the prompt text"
                            value={form.prompt}
                            onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => upd('prompt', e.target.value)}
                        />
                    </FormField>
                </Box>
            )}
        </StandardDialog>
    );
};

import React, { useState } from 'react';
import { Box, Typography, IconButton, useTheme } from '@mui/material';
import { Star, StarOutline, StarHalf } from '@mui/icons-material';

interface StarsDisplayProps {
    rating: number;
    size?: number;
}

export const StarsDisplay: React.FC<StarsDisplayProps> = ({ rating, size = 11 }) => {
    const full = Math.floor(rating);
    const half = rating - full >= 0.5;

    return (
        <Box sx={{ display: 'inline-flex', alignItems: 'center', gap: 0.25 }}>
            {[...Array(5)].map((_, i) => {
                const active = i < full || (i === full && half);
                const sx = {
                    fontSize: size,
                    color: active ? 'text.primary' : 'text.disabled',
                };
                if (i < full) return <Star key={i} sx={sx} />;
                if (i === full && half) return <StarHalf key={i} sx={sx} />;
                return <StarOutline key={i} sx={sx} />;
            })}
            <Typography
                variant="caption"
                sx={{
                    ml: 0.5,
                    fontSize: size - 1,
                    color: 'text.secondary',
                    fontFamily: 'monospace',
                }}
            >
                {rating.toFixed(1)}
            </Typography>
        </Box>
    );
};

interface InteractiveRatingProps {
    onRate: (rating: number) => void;
    userRating: number;
}

export const InteractiveRating: React.FC<InteractiveRatingProps> = ({ onRate, userRating }) => {
    const [hoverStar, setHoverStar] = useState(0);
    const theme = useTheme();

    return (
        <Box
            sx={{
                bgcolor: 'action.hover',
                borderRadius: 1,
                p: 1.5,
                border: '1px solid',
                borderColor: 'divider',
                mb: 2.5,
                display: 'flex',
                alignItems: 'center',
                gap: 1.5,
            }}
        >
            <Typography variant="overline" color="text.disabled" sx={{ fontWeight: 600 }}>
                Rate
            </Typography>
            <Box sx={{ display: 'flex', gap: 0.5 }}>
                {[1, 2, 3, 4, 5].map((s) => {
                    const active = hoverStar >= s || userRating >= s;
                    return (
                        <IconButton
                            key={s}
                            onMouseEnter={() => setHoverStar(s)}
                            onMouseLeave={() => setHoverStar(0)}
                            onClick={() => onRate(s)}
                            size="small"
                            sx={{
                                p: 0.25,
                                color: active ? 'text.primary' : 'text.disabled',
                                transition: 'transform 0.1s ease',
                                '&:hover': { transform: 'scale(1.1)', bgcolor: 'transparent' }
                            }}
                        >
                            {active
                                ? <Star sx={{ fontSize: 18 }} />
                                : <StarOutline sx={{ fontSize: 18 }} />
                            }
                        </IconButton>
                    );
                })}
            </Box>
            {userRating > 0 && (
                <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 600 }}>
                    Thanks!
                </Typography>
            )}
        </Box>
    );
};

import React, { useState } from 'react';
import {
    Box,
    Typography,
    Chip,
    Autocomplete,
    TextField,
    alpha
} from '@mui/material';
import { FormField } from '@som/ui';
import { ALL_TAGS } from '../../data/mockItems';

interface TagInputProps {
    tags: string[];
    setTags: (tags: string[]) => void;
}

export const TagInput: React.FC<TagInputProps> = ({ tags, setTags }) => {
    return (
        <FormField label="Tags">
            <Autocomplete
                multiple
                freeSolo
                size="small"
                options={ALL_TAGS}
                value={tags}
                onChange={(_, newValue) => setTags(newValue as string[])}
                renderTags={(value: string[], getTagProps) =>
                    value.map((option: string, index: number) => (
                        <Chip
                            variant="outlined"
                            label={option}
                            {...getTagProps({ index })}
                            sx={{
                                height: 20,
                                fontSize: '10px',
                                fontFamily: 'monospace',
                                bgcolor: alpha('#D4845A', 0.1),
                                color: '#D4845A',
                                borderColor: alpha('#D4845A', 0.2),
                                '& .MuiChip-deleteIcon': {
                                    fontSize: 12,
                                    color: alpha('#D4845A', 0.5),
                                    '&:hover': { color: '#D4845A' }
                                }
                            }}
                        />
                    ))
                }
                renderInput={(params) => (
                    <TextField
                        {...params}
                        placeholder={tags.length === 0 ? "e.g. facade, parametric..." : ""}
                        sx={{
                            '& .MuiInputBase-root': {
                                bgcolor: 'background.default',
                                fontSize: '12px',
                            }
                        }}
                    />
                )}
                sx={{
                    '& .MuiAutocomplete-endAdornment': { display: 'none' }
                }}
            />
        </FormField>
    );
};

import React from 'react';
import { useAtom, useAtomValue, useSetAtom } from 'jotai';
import { Box, Typography, Grid } from '@mui/material';
import { sectionLabelSx } from '@som/ui';
import { searchAtom } from '../atoms/filterAtoms';
import {
    selectedItemAtom,
    showSubmitAtom,
    showAboutAtom,
    showReqAtom,
} from '../atoms/modalAtoms';
import { useFilter } from '../hooks/useFilter';
import { HeroSection } from '../components/hero/HeroSection';
import { LibraryFilterBar } from '../components/filters/LibraryFilterBar';
import { PopularSection } from '../components/cards/PopularSection';
import { ResourceCard } from '../components/cards/ResourceCard';
import { ResourceDetailModal } from '../components/modals/ResourceDetailModal';
import { ContributeModal } from '../components/modals/ContributeModal';
import { RequestModal } from '../components/modals/RequestModal';
import { AboutPanel } from '../components/modals/AboutPanel';

const SecHead: React.FC<{ title: string; count: number; sub: string }> = ({ title, count, sub }) => (
    <Box sx={{ mb: 2, animation: 'fadeUp 0.4s ease both' }}>
        <Box sx={{ display: 'flex', alignItems: 'baseline', gap: 1 }}>
            <Typography variant="h2" component="h2">
                {title}
            </Typography>
            <Typography variant="caption" color="text.disabled" sx={{ fontFamily: 'monospace' }}>
                ({count})
            </Typography>
        </Box>
        <Typography variant="body2" color="text.secondary" sx={{ mt: 0.25 }}>
            {sub}
        </Typography>
    </Box>
);

export const AILibraryPage: React.FC = () => {
    const [selected, setSelected] = useAtom(selectedItemAtom);
    const [showSubmit, setShowSubmit] = useAtom(showSubmitAtom);
    const [showAbout, setShowAbout] = useAtom(showAboutAtom);
    const showReq = useAtomValue(showReqAtom);
    const setSearch = useSetAtom(searchAtom);

    const { useItems, learnItems, total } = useFilter();

    const handleAuthorClick = (author: string) => {
        setSearch(author);
    };

    return (
        <Box sx={{ maxWidth: 1360, mx: 'auto', px: { xs: 2, sm: 3, md: 4.5 } }}>
            <HeroSection />
            <PopularSection onSelect={setSelected} />
            <LibraryFilterBar total={total} />

            {/* Use Section */}
            {useItems.length > 0 && (
                <Box component="section" sx={{ mb: 4.5 }}>
                    <SecHead
                        title="Use"
                        count={useItems.length}
                        sub="Tools, prompts, and workflows ready to use today"
                    />
                    <Grid container spacing={1.25}>
                        {useItems.map((item, i) => (
                            <Grid item xs={12} sm={6} md={4} key={item.id}>
                                <ResourceCard item={item} index={i} onClick={setSelected} />
                            </Grid>
                        ))}
                    </Grid>
                </Box>
            )}

            {/* Learn Section */}
            {learnItems.length > 0 && (
                <Box component="section" sx={{ mb: 4.5 }}>
                    <SecHead
                        title="Learn"
                        count={learnItems.length}
                        sub="Case studies, tutorials, and methodology guides"
                    />
                    <Grid container spacing={1.25}>
                        {learnItems.map((item, i) => (
                            <Grid item xs={12} sm={6} md={4} key={item.id}>
                                <ResourceCard item={item} index={i} onClick={setSelected} />
                            </Grid>
                        ))}
                    </Grid>
                </Box>
            )}

            {/* Empty state */}
            {total === 0 && (
                <Box sx={{ textAlign: 'center', py: 8, animation: 'fadeUp 0.3s ease' }}>
                    <Typography variant="h1" sx={{ mb: 1.5, opacity: 0.3 }}>∅</Typography>
                    <Typography variant="body1" color="text.secondary">
                        No resources match your filters. Try adjusting your search.
                    </Typography>
                </Box>
            )}

            {/* Modals */}
            {selected && (
                <ResourceDetailModal
                    item={selected}
                    onClose={() => setSelected(null)}
                    onAuthorClick={handleAuthorClick}
                />
            )}
            {showSubmit && <ContributeModal onClose={() => setShowSubmit(false)} />}
            {showAbout && <AboutPanel onClose={() => setShowAbout(false)} />}
            {showReq && <RequestModal />}
        </Box>
    );
};
